import os; from pymongo import MongoClient
c=MongoClient(os.environ['MONGO_URL']); col=c['spis_castle_paid']['tour_stops']

T={
1:{"sk":("Vitajte na Spišskom hrade","Hlavný vstup a úvod do hradného komplexu","Vitajte v jednom z najväčších hradných komplexov v Európe. Vitajte v najväčšej pamiatke s výnimočnou architektúrou, ktorá je príkladom stavebného vývoja hradu v rôznych slohových obdobiach. Vitajte na Spišskom hrade, ktorý prešiel postupnou premenou z kráľovského hradu cez šľachtické sídlo až na vojenskú pevnosť. Prosím, posuňte sa ďalej do stredu tohto nádvoria k stanom, kde vpravo pod múrom je fotografia celého hradného komplexu z výšky. Prosím, dávajte pozor pod nohami, pretože vystupujú kamene a na chodníku je klzko, rovnako ako vo vnútri veže."),"en":("Welcome to Spiš Castle","Main entrance and introduction to the castle complex","Welcome to one of the largest castle complexes in Europe. Welcome to the largest monument with its exceptional architecture, which is an example of the construction development of the castle in different stylistic periods. Welcome to Spiš Castle, which has undergone a gradual transformation from a royal castle, through a noble residence, to a military fortress. Please move further into the middle of this courtyard to the tents, where on the right, under the wall, there is a photograph of the entire castle complex from a height. Please be careful under your feet because there are stones sticking out and it is slippery on the sidewalk as well as inside the tower."),"de":("Willkommen auf Burg Spiš","Haupteingang und Einführung in den Burgkomplex","Willkommen in einem der größten Burgkomplexe Europas. Die Zipser Burg hat eine schrittweise Verwandlung von einer königlichen Burg über eine Adelsresidenz zu einer Militärfestung durchlaufen. Bitte bewegen Sie sich weiter in die Mitte dieses Hofes zu den Zelten, wo sich rechts unter der Mauer eine Fotografie des gesamten Burgkomplexes aus der Höhe befindet. Bitte achten Sie auf Ihren Weg, da Steine herausragen und der Gehweg sowie das Innere des Turms rutschig sind."),"pl":("Witamy na Zamku Spiskim","Główne wejście i wprowadzenie do kompleksu zamkowego","Witamy w jednym z największych kompleksów zamkowych w Europie. Zamek Spiski przeszedł stopniową przemianę z zamku królewskiego, przez szlachecką rezydencję, do wojskowej twierdzy. Proszę przejść dalej na środek tego dziedzińca do namiotów, gdzie po prawej stronie, pod murem, znajduje się fotografia całego kompleksu zamkowego z wysokości. Proszę uważać na nogi, ponieważ wystają kamienie i jest ślisko."),"hu":("Üdvözöljük a Szepesi várban","Főbejárat és bevezetés a várkomplexumba","Üdvözöljük Európa egyik legnagyobb várkomplexumában. A Szepesi vár fokozatosan alakult át királyi várból nemesi rezidencián át katonai erőddé. Kérem, menjenek tovább az udvar közepére a sátrakhoz, ahol jobbra, a fal alatt, egy fénykép látható az egész várkomplexumról magasból. Kérem, vigyázzanak a lábukra, mert kövek állnak ki és csúszós a járda."),"fr":("Bienvenue au Château de Spiš","Entrée principale et introduction au complexe du château","Bienvenue dans l'un des plus grands complexes de châteaux d'Europe. Le Château de Spiš a subi une transformation progressive d'un château royal, en passant par une résidence noble, pour devenir une forteresse militaire. Veuillez vous déplacer au milieu de cette cour vers les tentes, où à droite, sous le mur, se trouve une photographie de l'ensemble du complexe depuis les hauteurs."),"es":("Bienvenido al Castillo de Spiš","Entrada principal e introducción al complejo del castillo","Bienvenido a uno de los complejos de castillos más grandes de Europa. El Castillo de Spiš ha experimentado una transformación gradual desde un castillo real, a través de una residencia noble, hasta una fortaleza militar. Por favor, avance hacia el centro de este patio hacia las tiendas, donde a la derecha, bajo la pared, hay una fotografía de todo el complejo desde las alturas."),"ru":("Добро пожаловать в Спишский Град","Главный вход и знакомство с замковым комплексом","Добро пожаловать в один из крупнейших замковых комплексов Европы. Спишский Град претерпел постепенное преобразование от королевского замка через дворянскую резиденцию до военной крепости. Пожалуйста, пройдите вглубь этого двора к палаткам, где справа, у стены, находится фотография всего замкового комплекса с высоты."),"zh":("欢迎来到斯皮什城堡","主入口及城堡建筑群介绍","欢迎来到欧洲最大的城堡建筑群之一。斯皮什城堡经历了从皇家城堡、贵族府邸到军事要塞的逐步转变。请走到这个庭院中间的帐篷处，在右侧墙壁下有一张整个城堡建筑群的高空照片。请注意脚下，人行道和塔楼内部都很滑。")},
2:{"sk":("Pred fotografiou hradu","Prehistorické osídlenie a počiatky hradu","Hradný kopec bol obývaný už v prehistorických dobách a neolite. Nálezy potvrdzujú bohaté osídlenie keltskými kmeňmi obchodujúcimi so sopečným sklom a obsidiánom. Boli vynikajúcimi hrnčiarmi a remeselníkmi. Hradisko na Spišskom vrchu slúžilo ako administratívne a hospodárske centrum tohto regiónu od nepamäti. Príbeh kráľovského hradu sa začal za vlády kráľa Bela III. na konci 12. storočia výstavbou veľkej obytnej pozorovacej veže Donžon na vrchole skalného výbežku. V roku 1221 sa hrad stal sídlom Kolomana Haličského z kráľovskej dynastie Arpádovcov."),"en":("In Front of the Castle Photograph","Prehistoric settlement and the beginnings of the castle","The castle hill was already inhabited in prehistoric times and the Neolithic period. The finds confirm the rich settlement by the Celtic tribes trading in volcanic glass and obsidian. They were excellent potters and craftsmen. The hillfort on Spišský vrch has served as the administrative and economic center of this region since time immemorial. The story of the royal castle began during the reign of King Bela III at the end of the 12th century with the construction of a large residential observation tower Donžon on top of a rocky outcrop. In 1221, the castle became the seat of Koloman of Galicia from the royal Árpád dynasty and slowly began to turn into a residence."),"de":("Vor der Burgfotografie","Prähistorische Besiedlung und die Anfänge der Burg","Der Burghügel war bereits in der Vorgeschichte bewohnt. Die Funde bestätigen die reiche Besiedlung durch keltische Stämme, die mit Vulkanglas und Obsidian handelten. Die Geschichte der königlichen Burg begann während der Herrschaft von König Béla III. am Ende des 12. Jahrhunderts mit dem Bau eines Beobachtungsturms Donžon auf einem Felsvorsprung. Im Jahr 1221 wurde die Burg Sitz von Koloman von Galizien aus der Árpáden-Dynastie."),"pl":("Przed fotografią zamku","Prehistoryczne osadnictwo i początki zamku","Wzgórze zamkowe było zamieszkane już w czasach prehistorycznych. Znaleziska potwierdzają bogate osadnictwo przez plemiona celtyckie handlujące szkłem wulkanicznym i obsydianem. Historia zamku królewskiego rozpoczęła się za panowania króla Béli III pod koniec XII wieku budową wieży obserwacyjnej Donžon na szczycie skalnego wystąpu. W 1221 roku zamek stał się siedzibą Kolomana Halickiego z dynastii Arpadów."),"hu":("A várkép előtt","Őskori település és a vár kezdetei","A várdomb már az őskorban is lakott volt. A leletek megerősítik a kelta törzsek gazdag letelepedését, akik vulkáni üveggel és obszidiánnal kereskedtek. A királyi vár története III. Béla király uralma idején kezdődött a 12. század végén egy Donžon torony építésével egy sziklakiugrón. 1221-ben a vár Galíciai Kálmán székhelye lett az Árpád-dinasztiából."),"fr":("Devant la photographie du château","Peuplement préhistorique et débuts du château","La colline du château était déjà habitée à l'époque préhistorique. Les trouvailles confirment le riche peuplement par les tribus celtes commerçant avec du verre volcanique et de l'obsidienne. L'histoire du château royal a commencé sous le règne du roi Béla III à la fin du XIIe siècle avec la construction d'une tour d'observation Donžon. En 1221, le château est devenu le siège de Koloman de Galice de la dynastie Árpád."),"es":("Frente a la fotografía del castillo","Asentamiento prehistórico y los comienzos del castillo","La colina del castillo ya estaba habitada en tiempos prehistóricos. Los hallazgos confirman el rico asentamiento por las tribus celtas que comerciaban con vidrio volcánico y obsidiana. La historia del castillo real comenzó durante el reinado del rey Béla III a finales del siglo XII con la construcción de la torre Donžon. En 1221, el castillo se convirtió en la sede de Koloman de Galicia de la dinastía Árpád."),"ru":("Перед фотографией замка","Доисторическое поселение и истоки замка","Замковая гора была заселена ещё в доисторические времена. Находки подтверждают богатое заселение кельтскими племенами, торговавшими вулканическим стеклом и обсидианом. История королевского замка началась в правление короля Белы III в конце XII века со строительства наблюдательной башни Донжон на скалистом выступе. В 1221 году замок стал резиденцией Коломана Галицкого из династии Арпадов."),"zh":("城堡照片前","史前定居点和城堡的起源","城堡山在史前时代就已有人居住。发现物证实了凯尔特部落的丰富定居，他们交易火山玻璃和黑曜石。城堡历史始于贝拉三世国王统治时期，12世纪末在岩石露头顶部建造了观察塔东荣。1221年，城堡成为阿尔帕德王朝加利西亚科洛曼的驻地。")},
3:{"sk":("Pri modeli hradu","História hradného komplexu a rodiny Csákyovcov","V tejto miestnosti môžete vidieť náčrty kresieb, ktoré ukazujú, že príbeh Spišského hradu začal výstavbou jednej obrannej veže a skončil tak, ako je znázornené na modeli Spišského hradu — konečný stav na začiatku 18. storočia, keď bol ešte obývaný. Model so 132 izbami vytvoril Adolph Stephanie. Na začiatku 18. storočia hrad prestal byť pohodlným sídlom. Štefan Csáky mal 26 detí s 2 ženami a rodina hrad opustila. Veľký požiar vypukol v roku 1870 — historici hovoria o troch teóriách vrátane podpálenia rodinou Csáky kvôli dani zo striech. Po 2. svetovej vojne bol hrad zoštátnený a v roku 1961 vyhlásený za národnú kultúrnu pamiatku."),"en":("At the Castle Model","History of the castle complex and the Csáky family","In this room you can see sketches showing that the story of Spiš Castle began with the construction of a single defensive tower and ended as shown in the Model of Spiš Castle — the final state at the beginning of the 18th century when it was still inhabited. The model of 132 rooms was created by Adolph Stephanie. At the beginning of the 18th century the castle ceased to be a comfortable manor house. Štefan Csáky had 26 children with 2 women and the family left the castle. The great fire broke out in 1870 — historians talk about three theories including arson by the Csáky family to avoid roof taxes. After World War II in 1945 the castle was nationalized and in 1961 declared a national cultural monument."),"de":("Am Burgmodell","Geschichte des Burgkomplexes und der Familie Csáky","In diesem Raum sehen Sie Skizzen, die die Geschichte der Zipser Burg zeigen — von einem einzelnen Turm bis zum Modell mit 132 Zimmern von Adolph Stephanie. Zu Beginn des 18. Jahrhunderts hörte die Burg auf, ein komfortables Herrenhaus zu sein. Štefan Csáky hatte 26 Kinder mit 2 Frauen und die Familie verließ die Burg. Der Brand von 1870 bleibt ungeklärt. Nach dem Zweiten Weltkrieg wurde die Burg verstaatlicht und 1961 zum nationalen Kulturdenkmal erklärt."),"pl":("Przy modelu zamku","Historia kompleksu zamkowego i rodziny Csáky","W tym pokoju można zobaczyć szkice pokazujące historię Zamku Spiskiego — od pojedynczej wieży do modelu ze 132 pokojami autorstwa Adolpha Stephanie. Na początku XVIII wieku zamek przestał być wygodną rezydencją. Štefan Csáky miał 26 dzieci z 2 kobietami i rodzina opuściła zamek. Wielki pożar z 1870 roku — trzy teorie. Po II wojnie światowej zamek został upaństwowiony i w 1961 roku uznany za narodowy zabytek kultury."),"hu":("A vármodellnél","A várkomplexum és a Csáky család története","Ebben a szobában vázlatrajzokat láthat a Szepesi vár történetéről — egyetlen toronytól az Adolph Stephanie által készített 132 szobás modelig. A 18. század elejére a vár elvesztette kényelmes kastélyjellegét. Štefan Csákynak 26 gyermeke volt 2 nőtől és a család elhagyta a várat. Az 1870-es tűz oka ismeretlen — három elmélet. A II. világháború után a várat államosították és 1961-ben nemzeti kulturális emlékké nyilvánították."),"fr":("Au modèle du château","Histoire du complexe du château et de la famille Csáky","Dans cette salle, vous voyez des esquisses de l'histoire du château — d'une seule tour au modèle de 132 pièces créé par Adolph Stephanie. Au début du XVIIIe siècle, le château a cessé d'être une demeure confortable. Štefan Csáky avait 26 enfants avec 2 femmes et la famille a quitté le château. L'incendie de 1870 reste inexpliqué. Après la Seconde Guerre mondiale, le château a été nationalisé et déclaré monument en 1961."),"es":("En el modelo del castillo","Historia del complejo del castillo y la familia Csáky","En esta sala puede ver bocetos de la historia del castillo — desde una sola torre hasta el modelo de 132 habitaciones de Adolph Stephanie. A principios del siglo XVIII el castillo dejó de ser una mansión cómoda. Štefan Csáky tuvo 26 hijos con 2 mujeres y la familia abandonó el castillo. El incendio de 1870 sin explicación. Después de la Segunda Guerra Mundial el castillo fue nacionalizado y declarado monumento en 1961."),"ru":("У модели замка","История замкового комплекса и семьи Чаки","В этом зале можно увидеть эскизы истории замка — от единственной башни до модели с 132 комнатами Адольфа Штефани. В начале XVIII века замок перестал быть удобной усадьбой. У Штефана Чаки было 26 детей от 2 жён и семья покинула замок. Причина пожара 1870 года — три теории. После Второй мировой войны замок был национализирован и в 1961 году объявлен национальным памятником."),"zh":("在城堡模型前","城堡建筑群历史和查基家族","在这个房间里，您可以看到城堡历史的素描——从单一塔楼到阿道夫·斯蒂芬尼创建的132个房间的模型。18世纪初，城堡不再是舒适的庄园。什特凡·查基与两名女性育有26个孩子，家族离开了城堡。1870年大火——三种理论。二战后城堡被国有化，1961年被宣布为国家文化古迹。")},
4:{"sk":("V kuchyni","Stredoveká kuchyňa a život na hrade","Základnou zložkou stravy bolo mäso — hydina, hovädzie, bravčové alebo zverina. Šľachta si vždy mohla dovoliť čerstvé mäso, kým ľudia z nižších vrstiev preferovali bravčové. Najčastejším spôsobom konzervovania bolo údenie, solenie a sušenie. Medzi obľúbené pochúťky patrili obilné kaše pripravované desiatkymi spôsobmi. Recept zo 16. storočia na štvorfarebnú kašu sa zachoval dodnes. Uhorská kuchyňa bola v celej Európe známa ako veľmi korenená. V čase pandémií pili všetci víno a pivo namiesto vody. Keď chcel pán hradu zaujať hostí, podávalo sa viacero chodov a stôl zdobil páv."),"en":("In the Kitchen","Medieval cuisine and life in the castle","The basic component of the diet was meat — poultry, beef, pork or game. The nobility could always afford fresh meat, while commoners preferred pork. The most common preservation methods were smoking, salting and drying. Among popular delicacies were cereal porridges prepared in dozens of ways. A recipe from the 16th century for the four-colored porridge has survived to this day. Hungarian cuisine in the Middle Ages was known throughout Europe as very spicy. At certain times during pandemics, all adults and children drank wine and beer instead of water. When the lord wanted to impress guests, several courses were served and the table was decorated with a peacock."),"de":("In der Küche","Mittelalterliche Küche und das Leben auf der Burg","Der Grundbestandteil der Ernährung war Fleisch — Geflügel, Rind, Schwein oder Wild. Der Adel konnte sich stets frisches Fleisch leisten. Die häufigsten Konservierungsmethoden waren Räuchern, Salzen und Trocknen. Beliebt waren Getreidebrei auf Dutzende Arten. In Zeiten von Pandemien tranken alle Wein und Bier statt Wasser."),"pl":("W kuchni","Średniowieczna kuchnia i życie na zamku","Podstawowym składnikiem diety było mięso — drób, wołowina, wieprzowina lub dziczyzna. Szlachta mogła sobie pozwolić na świeże mięso. Najpopularniejsze metody konserwowania to wędzenie, solenie i suszenie. Popularne były kasze zbożowe na dziesiątki sposobów. W czasie pandemii wszyscy pili wino i piwo zamiast wody."),"hu":("A konyhában","Középkori konyha és élet a várban","Az étrend alapvető összetevője a hús volt — baromfi, marha, sertés vagy vad. A nemesség mindig megengedhette magának a friss húst. A legnépszerűbb tartósítási módok a füstölés, sózás és szárítás. Járványok idején mindenki bort és sört ivott víz helyett."),"fr":("Dans la cuisine","Cuisine médiévale et vie au château","La composante de base de l'alimentation était la viande — volaille, bœuf, porc ou gibier. Les méthodes de conservation les plus courantes étaient le fumage, le salage et le séchage. Les bouillies de céréales préparées de dizaines de façons étaient populaires. En temps de pandémies, tous buvaient du vin et de la bière au lieu de l'eau."),"es":("En la cocina","Cocina medieval y vida en el castillo","El componente básico de la dieta era la carne — aves, ternera, cerdo o caza. Los métodos de conservación más comunes eran el ahumado, la salazón y el secado. Eran populares las papillas de cereales de docenas de maneras. En tiempo de pandemias todos bebían vino y cerveza en lugar de agua."),"ru":("На кухне","Средневековая кухня и жизнь в замке","Основным компонентом питания было мясо — птица, говядина, свинина или дичь. Наиболее распространёнными способами сохранения были копчение, соление и сушка. Популярными были зерновые каши десятками способов. Во время пандемий все пили вино и пиво вместо воды."),"zh":("在厨房","中世纪烹饪和城堡生活","饮食的基本成分是肉类——家禽、牛肉、猪肉或野味。最常见的保存方式是熏制、腌制和干燥。各种方式制作的谷物粥非常受欢迎。在瘟疫期间，所有人都喝葡萄酒和啤酒而不是水。")},
5:{"sk":("Na dolnej terase","Lokalita svetového dedičstva UNESCO a okolie","Na stenách môžeme vidieť fotografie vyjadrujúce dôvody, prečo bola celá táto oblasť zapísaná na Zoznam svetového kultúrneho a prírodného dedičstva UNESCO v roku 1993, spolu s ranostredovekou gotickou Kostolíkom sv. Ducha v Žehre. Spišský hrad tvorí centrum tejto jedinečnej oblasti a po mnoho rokov bol centrom svetskej moci na Spiši. V roku 2009 bola do zoznamu pridaná aj Levoča, kde možno obdivovať nádherný oltár Majstra Pavla a krásne sochy v Kostole sv. Jakuba. Z tejto terasy možno vidieť väčšinu toho, čo je na fotografiách."),"en":("On the Lower Terrace","UNESCO World Heritage Site and surroundings","On the walls we can see photographs expressing why this entire area was inscribed on the UNESCO World Cultural and Natural Heritage List in 1993, along with the early Gothic church of the Holy Spirit in Žehra. Spiš Castle forms the center of this unique area and for many years was the center of secular power in Spiš. In 2009, Levoča was also added to the list, where you can admire the magnificent altar by Master Pavol and the beautiful sculptures in the church of St. James. Mostly everything from the photographs can be seen from this terrace in person."),"de":("Auf der unteren Terrasse","UNESCO-Weltkulturerbe und Umgebung","An den Wänden sehen wir Fotografien, die zeigen, warum dieses Gebiet 1993 in die UNESCO-Liste aufgenommen wurde, zusammen mit der frühgotischen Kirche des Heiligen Geistes in Žehra. Im Jahr 2009 wurde auch Levoča zur Liste hinzugefügt, wo man den prächtigen Altar von Meister Pavol bewundern kann."),"pl":("Na dolnym tarasie","Obiekt Światowego Dziedzictwa UNESCO i okolice","Na ścianach możemy zobaczyć fotografie pokazujące, dlaczego cały ten obszar został wpisany na Listę UNESCO w 1993 roku, wraz z wczesnogotyckim kościołem Ducha Świętego w Žehrze. W 2009 roku do listy dodano również Lewoczę, gdzie można podziwiać ołtarz Mistrza Pawła."),"hu":("Az alsó teraszon","UNESCO Világörökség és környéke","A falakon fényképeket láthatunk, amelyek kifejezik, miért vette fel az UNESCO 1993-ban ezt az egész területet a listájára, a Žehrai Szentlélek-templommal együtt. 2009-ben Lőcsét is felvették a listára, ahol megcsodálhatja Pavol mester oltárát."),"fr":("Sur la terrasse inférieure","Site du patrimoine mondial de l'UNESCO et environs","Sur les murs, nous voyons des photographies expliquant pourquoi cette zone a été inscrite sur la liste de l'UNESCO en 1993, avec l'église gothique primitive du Saint-Esprit à Žehra. En 2009, Levoča a également été ajoutée, où vous pouvez admirer l'autel du Maître Pavol."),"es":("En la terraza inferior","Patrimonio Mundial de la UNESCO y alrededores","En las paredes vemos fotografías que explican por qué esta área fue inscrita en la lista de la UNESCO en 1993, junto con la iglesia gótica del Espíritu Santo en Žehra. En 2009, Levoča también fue añadida, donde puede admirar el altar del Maestro Pavol."),"ru":("На нижней террасе","Объект Всемирного наследия ЮНЕСКО и окрестности","На стенах мы видим фотографии, объясняющие, почему вся эта территория была внесена в список ЮНЕСКО в 1993 году, вместе с раннеготической церковью Святого Духа в Жехре. В 2009 году в список была добавлена также Левоча, где можно полюбоваться алтарём Мастера Павла."),"zh":("在下层露台","联合国教科文组织世界遗产地及周边环境","在墙壁上，我们可以看到照片，说明为什么整个地区在1993年被列入联合国教科文组织世界遗产名录，连同热赫拉的早期哥特式圣灵教堂。2009年，莱沃恰也被加入名单，在那里您可以欣赏帕沃尔大师的祭坛。")},
6:{"sk":("Na románskom predhradí","Najstaršia časť hradu a legenda o tatárskom vpáde","Vstúpili ste cez najstaršiu románsku bránu a stojíte na mieste spojenom s vpádom Tatárov a prvou písomnou zmienkou o hrade z roku 1249. Táto časť hradu bola postavená po roku 1241, keď Mongoli vtrhli do Uhorska a vyplienili celé okolie. Nepriatelia Spišský hrad nedobyli, pravdepodobne preto, že bol postavený z kameňa. Situácia sa zmenila, keď Matej Korvín daroval hrad rodine Zápoľskovcov, ktorí ho modernizovali v duchu neskorej gotiky. Vypočujte si legendu o tatárskej princeznej Šad — príbeh lásky medzi obrancom hradu a tatárskou princeznou počas obliehania v roku 1241."),"en":("On the Romanesque Forecourt","The oldest part of the castle and the Tatar invasion legend","You have entered through the oldest Romanesque gate, standing at a place associated with the invasion of the Tatars and the first written record of the castle from 1249. This part of the castle was built after 1241 when the Mongols invaded Hungary and plundered the entire surrounding countryside. The enemies did not conquer Spiš Castle, probably because it was made of stone. The situation changed when Matthias Corvinus donated the castle to the Zápoľský family, who modernized it in the spirit of late Gothic. Listen to the legend of the Tatar princess Šad — a story of love between a castle defender and a Tatar princess during the siege of 1241."),"de":("Auf dem romanischen Vorhof","Der älteste Teil der Burg und die Legende vom Tatarensturm","Sie haben das älteste romanische Tor betreten, einen Ort der mit dem Tatarensturm und der ersten schriftlichen Erwähnung der Burg von 1249 verbunden ist. Dieser Teil wurde nach 1241 erbaut, als die Mongolen Ungarn überfielen. Die Feinde haben die Burg nicht erobert. Matthias Corvinus schenkte die Burg später der Familie Zápoľský. Hören Sie sich die Legende der tatarischen Prinzessin Šad an."),"pl":("Na romańskim przedzamczu","Najstarsza część zamku i legenda o najeździe tatarskim","Weszliście przez najstarszą romańską bramę, w miejscu związanym z najazdem Tatarów i pierwszą pisemną wzmianką o zamku z 1249 roku. Ta część powstała po 1241 roku, gdy Mongołowie najechali Węgry. Wrogom nie udało się zdobyć zamku. Posłuchajcie legendy o tatarskiej księżniczce Šad."),"hu":("A román előudvaron","A vár legrégebbi része és a tatár betörés legendája","A legrégebbi román kapun lépett be, egy helyen, amely a tatárok betöréséhez és a vár 1249-es első írásos emlékéhez kapcsolódik. Ez a rész 1241 után épült, amikor a mongolok megtámadták Magyarországot. Az ellenségeknek nem sikerült elfoglalni a várat. Hallgassák meg Šad tatár hercegnő legendáját."),"fr":("Sur la cour romane","La partie la plus ancienne du château et la légende de l'invasion tatare","Vous avez franchi la plus ancienne porte romane, associée à l'invasion tatare et à la première mention écrite du château de 1249. Cette partie fut construite après 1241, quand les Mongols envahirent la Hongrie. Les ennemis n'ont pas conquis le château. Écoutez la légende de la princesse tatare Šad."),"es":("En el patio románico","La parte más antigua del castillo y la leyenda de la invasión tártara","Ha entrado por la puerta románica más antigua, asociada con la invasión tártara y la primera mención escrita del castillo de 1249. Esta parte fue construida después de 1241, cuando los mongoles invadieron Hungría. Los enemigos no pudieron conquistar el castillo. Escuche la leyenda de la princesa tártara Šad."),"ru":("На романском предворье","Старейшая часть замка и легенда о татарском нашествии","Вы вошли через старейшие романские ворота, место, связанное с татарским нашествием и первым письменным упоминанием о замке 1249 года. Эта часть была построена после 1241 года, когда монголы вторглись в Венгрию. Врагам не удалось завоевать замок. Послушайте легенду о татарской принцессе Шад."),"zh":("在罗马式前院","城堡最古老的部分和鞑靼入侵传说","您穿过最古老的罗马式大门，站在一个与鞑靼入侵和1249年城堡第一次书面记录相关的地方。这部分建于1241年之后，当时蒙古人入侵匈牙利。敌人没能攻占城堡。聆听鞑靼公主沙德的传说。")},
7:{"sk":("Na hornej terase","Panoramatický výhľad na región Spiš a Tatry","Spišský hrad stojí na vrchole travertínovej skaly v nadmorskej výške 634 m nad morom. Takmer kolmé steny kopca robili z tohto miesta jeden z najlepšie chránených hradov v krajine. V minulosti pod hradným kopcom viedli dve dôležité obchodné cesty — jedna spájala južnú Európu s Poľskom a Baltom, druhá Slovensko od západu na východ. Z tejto vyhliadky môžete vidieť takmer polovicu slovenských hôr: Branisko, Nízke Tatry, Kriváň, Vysoké Tatry a Levočské vrchy. Vidíte tiež dvojvežovú Katedrálu sv. Martina na Spišskej Kapitule a Dreveník naľavo."),"en":("On the Upper Terrace","Panoramic view of Spiš region and the Tatras","Spiš Castle stands on top of a travertine rock at an altitude of 634 m above sea level. The almost perpendicular walls of the hill made this place one of the best protected castles in the country. In the past, two important trade routes ran under the castle hill. From this lookout you can see almost half of the Slovak mountains: the Branisko Mountains, the Low Tatras, Kriváň Peak, the High Tatras and the Levoča Mountains. You can also see the twin-towered Cathedral of St. Martin in Spišská Kapitula and the Dreveník hill to the left."),"de":("Auf der oberen Terrasse","Panoramablick auf die Zips-Region und die Tatra","Die Zipser Burg steht auf einem Travertinfelsen in 634 m Höhe. Von diesem Aussichtspunkt sehen Sie fast die Hälfte der slowakischen Berge: Branisko, Niedere Tatra, Kriváň, Hohe Tatra und Levoča-Gebirge. Sie sehen auch die zweitürmige Kathedrale St. Martin in Spišská Kapitula."),"pl":("Na górnym tarasie","Panoramiczny widok na region Spiszu i Tatry","Zamek Spiski stoi na szczycie trawertynowej skały na wysokości 634 m n.p.m. Z tego punktu widokowego widać prawie połowę słowackich gór: Branisko, Niżne Tatry, Krywań, Tatry Wysokie i Góry Lewockie. Widać również dwuwieżową katedrę św. Marcina w Spišskiej Kapitule."),"hu":("A felső teraszon","Panorámás kilátás a Szepességre és a Tátrára","A Szepesi vár egy travertinszikla tetején áll 634 méter magasságban. Erről a kilátóról a szlovák hegység majdnem felét láthatja: Branisko, Alacsony-Tátra, Kriváň, Magas-Tátra és Lőcsei-hegység. Látható a kéttornyú Szent Márton székesegyház a Szepeshelyen is."),"fr":("Sur la terrasse supérieure","Vue panoramique sur la région de Spiš et les Tatras","Le château de Spiš se dresse sur une roche de travertin à 634 m d'altitude. De ce belvédère, vous voyez presque la moitié des montagnes slovaques: Branisko, Basses Tatras, Kriváň, Hautes Tatras et monts Levoča. On voit aussi la cathédrale à deux tours de Spišská Kapitula."),"es":("En la terraza superior","Vista panorámica de la región de Spiš y los Tatras","El Castillo de Spiš se alza sobre una roca de travertino a 634 m. Desde este mirador ve casi la mitad de las montañas eslovacas: Branisko, Bajos Tatras, Kriváň, Altos Tatras y montes Levoča. También se ve la catedral de dos torres de Spišská Kapitula."),"ru":("На верхней террасе","Панорамный вид на регион Спиш и Татры","Спишский Град стоит на травертиновой скале на высоте 634 м. С этой смотровой площадки видно почти половину словацких гор: Браниско, Низкие Татры, Кривань, Высокие Татры и горы Левоча. Виден также двухбашенный собор Святого Мартина в Спишской Капитуле."),"zh":("在上层露台","斯皮什地区和塔特拉山的全景","斯皮什城堡矗立在海拔634米的石灰华岩石顶部。从这个瞭望台可以看到几乎一半的斯洛伐克山脉：布拉尼斯科山、低塔特拉山、克里旺峰、高塔特拉山和莱沃恰山。还可以看到斯皮什卡皮图拉双塔圣马丁大教堂。")},
8:{"sk":("Dolné nádvorie","Najmladšia časť hradu postavená Jánom Jiskrom","Odtiaľto je krásny výhľad na celé dolné nádvorie postavené v polovici 15. storočia. V ľavom rohu nádvoria možno vidieť kamenné základy pozostatkov keltskej svätyne. Vznik dolného nádvoria sa spája s menom českého šľachtica Jána Jiskru z Brandýsa, ktorý k nám prišiel keď v Uhorsku vypukla občianska vojna. Po získaní hradu dal Jiskra pre svojich vojakov postaviť vojenský tábor obohnaný múrmi vysokými 7 až 9 m a hrubými až tri metre. Mohutné múry sú prerušené dvoma štvorcovými obrannými strážnymi vežami. Vo veži vpravo sa nachádza expozícia mučiarne. V ľavej veži sú informácie o divých zvieratách, ako sú sysle, a o susednom kopci Dreveník."),"en":("Lower Courtyard","The youngest part of the castle built by Jan Jiskra","From here there is a beautiful view of the entire lower courtyard built in the mid-15th century. In the left corner you can see the stone foundations of a Celtic sanctuary. The creation of the lower courtyard is connected with the Czech nobleman Ján Jiskra of Brandýs, who came here when civil war broke out in Hungary. After acquiring the castle, Jiskra had a military camp built for his soldiers, surrounded by large walls 7 to 9 m high and up to three meters thick. The walls are interrupted by two square defensive watchtowers. In the right tower there is an exhibition of the torture chamber. In the left tower there is information about wild animals such as ground squirrels and the neighboring Dreveník hill."),"de":("Unterer Burghof","Der jüngste Teil der Burg, erbaut von Jan Jiskra","Von hier aus hat man einen schönen Blick auf den gesamten unteren Burghof aus der Mitte des 15. Jahrhunderts. In der linken Ecke sieht man Steinfundamente eines keltischen Heiligtums. Der Hof ist mit Ján Jiskra von Brandýs verbunden. Jiskra ließ einen Militärlager bauen, mit Mauern 7-9 m hoch. Im rechten Turm gibt es die Folterkammerausstellung, im linken Informationen über Wildtiere und den Dreveník-Hügel."),"pl":("Dolny dziedziniec","Najmłodsza część zamku zbudowana przez Jana Jiskrę","Stąd roztacza się piękny widok na cały dolny dziedziniec z połowy XV wieku. W lewym rogu widać kamienne fundamenty celtyckiej świątyni. Dziedziniec wiąże się z Jánem Jiskrą z Brandýs. Jiskra zbudował obóz wojskowy z murami 7-9 m wysokimi. W prawej wieży jest ekspozycja izby tortur, w lewej informacje o dzikich zwierzętach i wzgórzu Dreveník."),"hu":("Alsó udvar","A vár legfiatalabb része, amelyet Jan Jiskra épített","Innen gyönyörű kilátás nyílik a 15. század közepén épült alsó udvarra. A bal sarokban kelta szentély kőalapjai láthatók. Az udvart Ján Jiskra cseh nemes nevéhez fűzik. Jiskra 7-9 méter magas falakkal övezett katonai tábort épített. A jobb toronyban kínzókamra-kiállítás, a balban vadállat- és Dreveník-domb információk láthatók."),"fr":("Cour inférieure","La partie la plus récente du château construite par Jan Jiskra","De là, belle vue sur la cour inférieure du milieu du XVe siècle. Dans le coin gauche, des fondations d'un sanctuaire celte. La cour est liée à Ján Jiskra de Brandýs. Jiskra fit construire un camp militaire avec des murs de 7-9 m de haut. Dans la tour droite, l'exposition de la chambre de torture; dans la gauche, informations sur la faune et la colline Dreveník."),"es":("Patio inferior","La parte más reciente del castillo construida por Jan Jiskra","Desde aquí, bella vista del patio inferior de mediados del siglo XV. En la esquina izquierda, cimientos de un santuario celta. El patio está ligado a Ján Jiskra de Brandýs. Jiskra construyó un campamento militar con muros de 7-9 m de alto. En la torre derecha, la exposición de la cámara de tortura; en la izquierda, información sobre fauna y la colina Dreveník."),"ru":("Нижний двор","Самая молодая часть замка, построенная Яном Йискрой","Отсюда красивый вид на нижний двор середины XV века. В левом углу видны каменные фундаменты кельтского святилища. Двор связан с чешским дворянином Яном Йискрой из Брандиса. Йискра построил военный лагерь со стенами высотой 7-9 м. В правой башне экспозиция пыточной камеры, в левой — информация о дикой природе и холме Древеник."),"zh":("下院","由扬·伊斯克拉建造的城堡最新部分","从这里可以看到15世纪中期建造的整个下院的美丽景色。左角可以看到凯尔特圣所的石制基础。下院与捷克贵族扬·伊斯克拉相连。伊斯克拉建造了高7至9米的军营围墙。右塔中有酷刑室展览，左塔中有关于野生动物和德列夫尼克山的信息。")},
9:{"sk":("Mučiareň","Stredoveká justícia a metódy vypočúvania","Mučiareň bola v minulosti neoddeliteľnou súčasťou súdneho systému — úplne normálny a legálny spôsob získavania svedectva alebo priznania. Bežne sa stávalo, že väzeň sa tak vyľakal už len pri pohľade na nástroje, že sa radšej priznal dobrovoľne. Mučenie mohlo trvať rôzne dlho a bolo veľmi účinnou metódou, ktorá takmer vždy vyústila do priznania. Nielen mučenie, ale aj samotný pobyt vo väzení bol utrpením — tmavá, studená, vlhká pivnica bez denného svetla, väzeň často pripútaný priamo k skale. Mučiace nástroje: paldy, husle, španielska čižma, skúška ohňom, kladka, dereš, vodný test, strapado a zlomenie kolesá."),"en":("Torture Chamber","Medieval justice and interrogation methods","The torture chamber was an integral part of the judicial system in the past — a completely normal and legal way to obtain testimony or confession. It was common for a prisoner to be so frightened that they would confess voluntarily just from seeing the instruments. Torture could last for varying lengths and was very effective, almost always resulting in a confession. Not only the torture, but also prison itself was suffering — the dark, cold, damp basement without daylight, prisoner often chained directly to the rock. Torture instruments included: the stocks, the violin, the Spanish boot, trial by fire, the pulley, the Dereš bench, the water test, Strapado, and breaking on the wheel."),"de":("Folterkammer","Mittelalterliche Justiz und Verhörmethoden","Die Folterkammer war ein integraler Bestandteil des Justizsystems — eine völlig normale und legale Methode, Geständnisse zu erlangen. Oft gestand ein Gefangener schon beim Anblick der Instrumente freiwillig. Die Folter war sehr effektiv. Nicht nur die Folter, sondern auch der Gefängnisaufenthalt war Leiden. Folterinstrumente: Pfahl, Violine, Spanische Stiefel, Feuerprobe, Rolle, Dereš, Wasserprobe, Strapado und das Rad."),"pl":("Sala tortur","Średniowieczne sądownictwo i metody przesłuchań","Sala tortur była integralną częścią systemu sądowniczego — całkowicie normalną i legalną metodą uzyskiwania zeznań. Często więzień, widząc tylko instrumenty, przyznawał się dobrowolnie. Tortury były bardzo skuteczne. Narzędzia: paldy, skrzypce, but hiszpański, próba ognia, bloczek, dereš, próba wodna, strapado i koło."),"hu":("Kínzókamra","Középkori igazságszolgáltatás és kihallgatási módszerek","A kínzókamra az igazságszolgáltatás szerves része volt — teljesen normális és legális módszer a vallomás megszerzésére. A fogoly már az eszközök láttán is önként vallott. A kínzás szinte mindig vallomással végződött. Kínzóeszközök: palda, hegedű, spanyolcsizma, tűzpróba, csiga, dereš, vízpróba, strapado és a kerék."),"fr":("Chambre de torture","Justice médiévale et méthodes d'interrogatoire","La chambre de torture faisait partie intégrante du système judiciaire — une méthode tout à fait normale et légale. Un prisonnier confessait souvent volontairement rien qu'à la vue des instruments. La torture aboutissait presque toujours à un aveu. Instruments: stocks, violon, botte espagnole, épreuve du feu, poulie, dereš, épreuve de l'eau, strapado et la roue."),"es":("Cámara de tortura","Justicia medieval y métodos de interrogatorio","La cámara de tortura era parte integral del sistema judicial — un método completamente normal y legal. Un prisionero a menudo confesaba voluntariamente solo al ver los instrumentos. La tortura casi siempre resultaba en confesión. Instrumentos: el paladín, violín, bota española, prueba del fuego, polea, dereš, prueba del agua, strapado y la rueda."),"ru":("Пыточная камера","Средневековое правосудие и методы допроса","Пыточная камера была неотъемлемой частью судебной системы — совершенно нормальный и законный способ получения признания. Заключённый часто признавался добровольно уже при виде инструментов. Пытки почти всегда приводили к признанию. Орудия: колодки, скрипка, испанский сапог, испытание огнём, блок, дереш, водное испытание, стрападо и колесо."),"zh":("酷刑室","中世纪司法和审讯方法","酷刑室是司法体系不可分割的一部分——完全正常合法的方式获取认罪。囚犯仅见到刑具就常常自愿认罪。酷刑几乎总是以认罪告终。酷刑工具：枷锁、小提琴、西班牙靴、火刑、滑轮、德雷什、水刑、绞刑架和轮刑。")},
10:{"sk":("V Zápoľskom paláci","Kuchyňa neskorogotických Zápoľských palácov","Prešli ste druhou románskou bránou, okolo zvyškov bašty a krásne zrekonštruovaného kapitánskeho domu, a ocitli ste sa pred Turzovskou bránou. S najväčšou pravdepodobnosťou stojíte v kuchyni pôvodných západných zápoľských palácov v renesančnom slohu — jediná miestnosť bez okien, ktorá slúžila ako priechod medzi miestnosťami. Ak sa pred vstupom do veže pozriete dole, uvidíte zvyšky prvej stavby z 12. storočia — rozsiahla kruhová kamenná veža postavená dynastiou Árpádovcov, s priemerom 4 metre a výškou 23 metrov. Kvôli tektonickým posunom veža padla. Až po jej páde začali stavať prvý hradný múr okolo celej akropoly."),"en":("In the Zápoľský Palace","The kitchen of the late Gothic Zápoľský palaces","You passed through the second Romanesque gate, past the remains of a bastion and the beautifully renovated captain's house, and found yourself in front of the Turzovo gate. You are most likely standing in the kitchen of the original western Zápoľský palaces in the Renaissance style — the only room without windows, which served as a passage between rooms. If you look below before entering the tower, you will see the remains of the first building from the 12th century — a large circular stone tower built by the Árpád dynasty, 4 meters in diameter and 23 meters high. Due to tectonic shifts, the tower collapsed. Only after its fall did they begin to build the first castle wall around the entire acropolis."),"de":("Im Zápoľský-Palast","Die Küche der spätgotischen Zápoľský-Paläste","Sie sind durch das zweite romanische Tor gegangen und stehen vor dem Turzovo-Tor. Sie befinden sich höchstwahrscheinlich in der Küche der Zápoľský-Paläste — der einzige Raum ohne Fenster. Wenn Sie vor dem Turm nach unten schauen, sehen Sie Reste des ersten Gebäudes aus dem 12. Jahrhundert — ein runder Steinturm der Árpáden, 4 Meter Durchmesser, 23 Meter hoch. Er fiel durch tektonische Verschiebungen."),"pl":("W Pałacu Zápoľskich","Kuchnia późnogotyckich pałaców Zápoľskich","Przeszliście przez drugą romańską bramę i znaleźliście się przed bramą Turzową. Najprawdopodobniej stoicie w kuchni pałaców Zápoľskich — jedyne pomieszczenie bez okien. Jeśli spojrzycie w dół przed wieżą, zobaczycie pozostałości pierwszego budynku z XII wieku — okrągła kamienna wieża Arpadów, 4 metry średnicy, 23 metry wysoka."),"hu":("A Zápoľský-palotában","A késő gótikus Zápoľský-paloták konyhája","A második román kapun át jutott a Turzó-kapuhoz. Valószínűleg a Zápoľský-paloták konyhájában áll — az egyetlen ablaktalan helyiség. Ha a torony előtt lenéz, láthatja a 12. századi első épület maradványait — az Árpádok kerek kőtornya, 4 méter átmérővel, 23 méter magasságban."),"fr":("Dans le palais Zápoľský","La cuisine des palais gothiques tardifs des Zápoľský","Vous êtes passé par la deuxième porte romane et vous vous trouvez devant la porte Turzovo. Vous êtes très probablement dans la cuisine des palais Zápoľský — la seule pièce sans fenêtre. Si vous regardez en bas avant la tour, vous verrez les restes du premier bâtiment du XIIe siècle — une tour ronde en pierre des Árpád, 4 mètres de diamètre, 23 mètres de haut."),"es":("En el Palacio Zápoľský","La cocina de los palacios góticos tardíos de los Zápoľský","Pasó por la segunda puerta románica y se encontró ante la puerta Turzovo. Probablemente está en la cocina de los palacios Zápoľský — la única habitación sin ventanas. Si mira abajo antes de la torre, verá los restos del primer edificio del siglo XII — una torre redonda de piedra de los Árpád, 4 metros de diámetro, 23 metros de alto."),"ru":("Во дворце Запольских","Кухня позднеготических дворцов Запольских","Вы прошли через вторые романские ворота и оказались перед Турзовскими воротами. Скорее всего, вы находитесь на кухне дворцов Запольских — единственная комната без окон. Если посмотреть вниз перед башней, видны остатки первого здания XII века — круглая каменная башня Арпадов, 4 метра в диаметре, 23 метра высотой."),"zh":("在扎波尔斯基宫殿","晚期哥特式扎波尔斯基宫殿的厨房","您穿过第二道罗马式大门，来到图尔佐沃大门前。您很可能站在扎波尔斯基宫殿的厨房里——唯一没有窗户的房间。如果在进入塔楼前向下看，您会看到12世纪第一座建筑的遗迹——阿尔帕德王朝的圆形石塔，直径4米，高23米。")},
11:{"sk":("Veža — Nebojsa","Posledné útočisko obrancov hradu","Súčasná 19-metrová hradná veža bola postavená uprostred už opevnenej akropoly namiesto starej, spolu s palácom. Slúžila len ako miesto poslednej obrany a nazývala sa Nebojsa. Postavil ju vojvoda Koloman, syn kráľa Ondreja II. Veža mala 5 poschodí vrátane suterénu na skladovanie zbraní a potravín. Prístup len po drevenom rebríku na prvé poschodie. Úzke schodisko v smere hodinových ručičiek sa na konci mení na protismerné — to bránilo nepriateľom držať meč v pravej ruke. Vo veži sa zachovala stredoveká toaleta z 13. storočia a na južnej strane zvyšky slnečných hodín. Cisterna vysekaná do skaly zbierala dažďovú vodu — jediný zdroj vody na hrade."),"en":("The Tower — Nebojsa","The last refuge of the castle defenders","The current 19-meter castle tower was built in the middle of the already fortified acropolis instead of the old one, together with the palace. It served only as a place of last defense and was called Nebojsa. Built by Duke Koloman, son of King Andrew II. The tower had 5 floors including the basement for storing weapons and food. Access was only by wooden ladder to the first floor. The narrow clockwise staircase turns counter-clockwise at the end — this prevented enemies from holding a sword in their right hand. A medieval toilet from the 13th century is preserved in the tower, and on the south side are remains of a sundial. A cistern carved into the rock collected rainwater — the only source of water in the castle."),"de":("Der Turm — Nebojsa","Die letzte Zuflucht der Burgverteidiger","Der heutige 19-Meter-Turm wurde in der Mitte der befestigten Akropolis errichtet. Er diente als letzter Verteidigungsort und wurde Nebojsa genannt. Gebaut von Herzog Koloman, Sohn von König Andreas II. Der Turm hatte 5 Stockwerke. Das schmale Treppenhaus dreht sich am Ende gegen den Uhrzeigersinn. Im Turm ein mittelalterliches WC aus dem 13. Jahrhundert und Sonnenuhr-Reste. Eine Felsenzisterne sammelte Regenwasser."),"pl":("Wieża — Nebojsa","Ostatnie schronienie obrońców zamku","Obecna 19-metrowa wieża służyła jako ostatnie miejsce obrany i nazywała się Nebojsa. Zbudował ją książę Koloman, syn króla Andrzeja II. Wieża miała 5 kondygnacji. Wąskie schody zmieniają kierunek na końcu. W wieży zachowała się toaleta z XIII wieku i resztki zegara słonecznego. Cysterna w skale zbierała deszczówkę."),"hu":("A torony — Nebojsa","A vár védőinek utolsó menedéke","A jelenlegi 19 méteres torony csak az utolsó védelmi helyként szolgált és Nebojsának hívták. II. András király fia, Kálmán herceg építtette. A szűk lépcső iránya az óramutató járásával ellentétesen változik a végén. A toronyban 13. századi toalett és napóra-maradványok. A sziklaciszterna esővizet gyűjtött."),"fr":("La tour — Nebojsa","Le dernier refuge des défenseurs","La tour actuelle de 19 mètres servait de dernier lieu de défense et s'appelait Nebojsa. Construite par le duc Koloman, fils du roi André II. L'escalier étroit tourne dans le sens antihoraire à la fin. Dans la tour, toilettes médiévales du XIIIe siècle et restes de cadran solaire. Une citerne dans le roc recueillait l'eau de pluie."),"es":("La torre — Nebojsa","El último refugio de los defensores","La torre actual de 19 metros servía como último bastión de defensa y se llamaba Nebojsa. Construida por el duque Koloman, hijo del rey Andrés II. La escalera gira en sentido contrario al final. En la torre, retrete medieval del siglo XIII y restos de reloj de sol. Una cisterna en la roca recogía agua de lluvia."),"ru":("Башня — Небойша","Последнее убежище защитников замка","Нынешняя 19-метровая башня служила последним местом обороны и называлась Небойша. Построена герцогом Коломаном, сыном короля Андраша II. Узкая лестница меняет направление в конце. В башне средневековый туалет XIII века и остатки солнечных часов. Высеченная в скале цистерна собирала дождевую воду."),"zh":("塔楼——内博亚萨","城堡守卫者的最后避难所","现在的19米高塔楼仅作为最后防御地点，称为Nebojsa。由安德烈二世之子科洛曼公爵建造。狭窄楼梯末端变为逆时针方向。塔楼中保存着13世纪的中世纪厕所和日晷遗迹。凿入岩石的蓄水池收集雨水。")},
12:{"sk":("Románsky palác","Jeden zo 4 svetských románskych palácov zachovaných na svete","Táto arkádová chodba je jediným vstupom do neskorogotickej kaplnky sv. Alžbety Uhorskej a slúži ako múzeum zbraní a brnení. V zadnej časti skalnatej plošiny stojí mohutný trojposchodový románsky palác — jeden zo 4 zachovaných svetských románskych palácov na svete. Ďalší je v talianskom Merane, odkiaľ pochádzala aj kráľovná Gertrúda, matka kniežaťa Kolomana. Palác bol postavený čo najďalej od hradnej brány, na najneprístupnejšej časti kopca. Spišský Špan — kráľovský správca Spiša — žil tu so svojou rodinou. Na prvom poschodí sa nachádza jedna veľká sála rozdelená dvoma radmi stĺpov, osvetlená siedmymi typickými románskymi oknami. Palác prešiel mnohými stavebnými úpravami, ale žiadna nezmenila jeho pôvodný románsky charakter."),"en":("Romanesque Palace","One of only 4 secular Romanesque palaces preserved in the world","This arcaded corridor is the only entrance to the late Gothic chapel of St. Elizabeth of Hungary and serves as a museum of weapons and armor. At the back of the rocky plateau stands a massive three-story Romanesque palace — one of only 4 preserved secular Romanesque palaces in the world. Another is in Merano, Italy, where Queen Gertrude, mother of Prince Koloman, also came from. The palace was built as far as possible from the castle gate, on the most inaccessible part of the hill. The Spišský Špan — the royal administrator of Spiš — lived here with his family. On the first floor is one large hall divided by two rows of columns, lit by seven typical Romanesque windows."),"de":("Romanischer Palast","Einer von nur 4 weltlichen romanischen Palästen der Welt","Dieser Arkadengang ist der einzige Eingang zur spätgotischen Kapelle der Hl. Elisabeth und Waffen- und Rüstungsmuseum. Am hinteren Teil des Felsplateaus steht ein massiver romanischer Palast — einer von nur 4 erhaltenen weltlichen romanischen Palästen weltweit. Ein weiterer befindet sich in Merano, Italien. Im ersten Stock ein großer Saal, durch zwei Säulenreihen geteilt, durch sieben romanische Fenster beleuchtet."),"pl":("Pałac romański","Jeden z zaledwie 4 świeckich pałaców romańskich zachowanych na świecie","Ten arkadowy korytarz jest jedynym wejściem do późnogotyckiej kaplicy św. Elżbiety Węgierskiej i muzeum broni i zbroi. W tylnej części płaskowyżu stoi masywny pałac romański — jeden z zaledwie 4 zachowanych świeckich pałaców romańskich na świecie. Kolejny jest w Merano we Włoszech. Na pierwszym piętrze wielka sala podzielona dwoma rzędami kolumn, oświetlona siedmioma oknami."),"hu":("Román stílusú palota","A világon megőrzött mindössze 4 világi román palota egyike","Ez az árkádos folyosó a késő gótikus Szent Erzsébet-kápolna egyetlen bejárata és fegyver- és páncélmúzeum. A sziklás fennsík hátsó részén masszív román palota áll — a világon megőrzött mindössze 4 világi román palota egyike. Egy másik az olaszországi Meranóban van. Az első emeleten nagy terem, két oszlopsorral osztva, hét román ablakkal megvilágítva."),"fr":("Palais roman","L'un des seulement 4 palais romans séculiers préservés dans le monde","Ce couloir arcadé est l'unique entrée de la chapelle gothique tardive de Sainte-Élisabeth et musée d'armes et d'armures. À l'arrière du plateau rocheux, un massif palais roman — l'un des seulement 4 palais romans séculiers préservés au monde. Un autre se trouve à Merano, Italie. Au premier étage, grande salle divisée par deux rangées de colonnes, éclairée par sept fenêtres romanes."),"es":("Palacio románico","Uno de solo 4 palacios románicos seculares preservados en el mundo","Este corredor de arcos es la única entrada a la capilla gótica tardía de Santa Isabel de Hungría y museo de armas y armaduras. En la parte posterior de la meseta rocosa, un macizo palacio románico — uno de solo 4 palacios románicos seculares conservados en el mundo. Otro está en Merano, Italia. En el primer piso, gran sala dividida por dos filas de columnas, iluminada por siete ventanas románicas."),"ru":("Романский дворец","Один из всего 4 светских романских дворцов, сохранившихся в мире","Этот аркадный коридор — единственный вход в позднеготическую часовню Святой Елизаветы Венгерской и музей оружия и доспехов. В задней части скалистого плато стоит массивный трёхэтажный романский дворец — один из всего 4 сохранившихся в мире светских романских дворцов. Другой находится в Мерано, Италия. На первом этаже большой зал, разделённый двумя рядами колонн, освещённый семью романскими окнами."),"zh":("罗马式宫殿","世界上仅存4座世俗罗马式宫殿之一","这条拱廊走廊是匈牙利圣伊丽莎白晚期哥特式礼拜堂的唯一入口，也是武器和盔甲博物馆。在岩石高原后部矗立着宏伟的三层罗马式宫殿——世界上仅存4座世俗性罗马式宫殿之一。另一座在意大利梅拉诺。一楼有一个大厅，仅由两排柱子分隔，被七个典型的罗马式窗户照亮。")},
}

updated=0
for stop_num,langs in T.items():
    s=col.find_one({'stop_number':stop_num})
    if not s: print(f'MISSING: stop {stop_num}'); continue
    ex={t['language_code']:t for t in s.get('translations',[])}
    for lc,(title,sd,desc) in langs.items():
        if lc in ex:
            ex[lc]['title']=title; ex[lc]['short_description']=sd; ex[lc]['description']=desc
        else:
            ex[lc]={'language_code':lc,'title':title,'short_description':sd,'description':desc,'audio_url':None,'video_url':None,'vr_url':None}
    r=col.update_one({'stop_number':stop_num},{'$set':{'translations':list(ex.values())}})
    if r.modified_count>0: print(f'OK: stop {stop_num}'); updated+=1
    else: print(f'NO CHANGE: stop {stop_num}')
print(f'DONE! Updated {updated} stops')
c.close()
